from click.testing import CliRunner

@click.command()
@click.option('--item', multiple=True, batch_size=2)
def cli(item):
    click.echo(repr(item))

runner = CliRunner()
result = runner.invoke(cli, ['--item', 'a', '--item', 'b', '--item', 'c', '--item', 'd', '--item', 'e'])
print(result.output)
print(result.exit_code)

